import React, { useState, useEffect } from 'react'
import { supabase } from '../../lib/supabaseClient'

export const Marketplace: React.FC = () => {
  const [listings, setListings] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [currentUser, setCurrentUser] = useState<any>(null)
  const [showCreateForm, setShowCreateForm] = useState(false)

  // Create listing form state
  const [formData, setFormData] = useState({
    item_name: '',
    description: '',
    price: '',
    condition: 'Good',
    category: ''
  })

  useEffect(() => {
    supabase.auth.getUser().then(({ data }) => setCurrentUser(data.user))
    loadListings()
  }, [])

  const loadListings = async () => {
    setLoading(true)
    const { data, error } = await supabase
      .from('marketplace')
      .select('*')
      .eq('status', 'AVAILABLE')
      .order('created_at', { ascending: false })

    if (!error) setListings(data || [])
    setLoading(false)
  }

  const handleCreateListing = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!currentUser) {
      alert('Please login first')
      return
    }

    const price = parseFloat(formData.price)
    if (isNaN(price) || price <= 0) {
      alert('Please enter a valid price')
      return
    }

    const { error } = await supabase
      .from('marketplace')
      .insert({
        seller_id: currentUser.id,
        item_name: formData.item_name,
        description: formData.description,
        price: price,
        condition: formData.condition,
        category: formData.category || 'Other',
        status: 'AVAILABLE'
      })

    if (error) {
      alert('Failed to create listing: ' + error.message)
    } else {
      alert('✅ Listing created successfully!')
      setShowCreateForm(false)
      setFormData({ item_name: '', description: '', price: '', condition: 'Good', category: '' })
      loadListings()
    }
  }

  const handleBuy = async (listing: any) => {
    if (!currentUser) {
      alert('Please login first')
      return
    }

    if (listing.seller_id === currentUser.id) {
      alert('You cannot buy your own item')
      return
    }

    if (listing.status !== 'AVAILABLE') {
      alert('This item is no longer available')
      return
    }

    if (window.confirm(`Buy "${listing.item_name}" for $${listing.price}?`)) {
      const { error } = await supabase
        .from('marketplace')
        .update({ status: 'SOLD' })
        .eq('id', listing.id)

      if (error) {
        alert('Purchase failed: ' + error.message)
      } else {
        alert(`✅ Purchased "${listing.item_name}" successfully!`)
        loadListings()
      }
    }
  }

  return (
    <div style={{
      minHeight: '100vh',
      background: '#0a0a0a',
      color: 'white',
      padding: '24px'
    }}>
      <div style={{ maxWidth: '900px', margin: '0 auto' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
          <div>
            <h1 style={{ color: '#FFD700', fontSize: '28px' }}>🛒 Marketplace</h1>
            <p style={{ color: '#666' }}>Buy & sell sports equipment</p>
          </div>
          <button
            onClick={() => setShowCreateForm(!showCreateForm)}
            style={{
              padding: '10px 20px',
              background: showCreateForm ? '#ff4444' : '#c8a200',
              color: showCreateForm ? 'white' : '#0a0a0a',
              border: 'none',
              borderRadius: '8px',
              fontWeight: 'bold',
              cursor: 'pointer'
            }}
          >
            {showCreateForm ? '✕ Cancel' : '+ Sell Item'}
          </button>
        </div>

        {/* Create Listing Form */}
        {showCreateForm && (
          <div style={{
            background: '#0d0d0d',
            border: '1px solid #c8a20020',
            borderRadius: '12px',
            padding: '24px',
            marginBottom: '24px'
          }}>
            <h3 style={{ color: '#FFD700', marginBottom: '16px' }}>📝 Create Listing</h3>
            <form onSubmit={handleCreateListing}>
              <div style={{ marginBottom: '12px' }}>
                <input
                  type="text"
                  value={formData.item_name}
                  onChange={(e) => setFormData({ ...formData, item_name: e.target.value })}
                  placeholder="Item name *"
                  style={{
                    width: '100%',
                    padding: '12px',
                    background: '#1a1a1a',
                    border: '1px solid #333',
                    borderRadius: '8px',
                    color: 'white',
                    fontSize: '14px'
                  }}
                  required
                />
              </div>
              <div style={{ marginBottom: '12px' }}>
                <textarea
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                  placeholder="Description"
                  rows={2}
                  style={{
                    width: '100%',
                    padding: '12px',
                    background: '#1a1a1a',
                    border: '1px solid #333',
                    borderRadius: '8px',
                    color: 'white',
                    fontSize: '14px',
                    fontFamily: 'inherit'
                  }}
                />
              </div>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', marginBottom: '12px' }}>
                <input
                  type="number"
                  value={formData.price}
                  onChange={(e) => setFormData({ ...formData, price: e.target.value })}
                  placeholder="Price ($) *"
                  step="0.01"
                  min="0.01"
                  style={{
                    padding: '12px',
                    background: '#1a1a1a',
                    border: '1px solid #333',
                    borderRadius: '8px',
                    color: 'white',
                    fontSize: '14px'
                  }}
                  required
                />
                <select
                  value={formData.condition}
                  onChange={(e) => setFormData({ ...formData, condition: e.target.value })}
                  style={{
                    padding: '12px',
                    background: '#1a1a1a',
                    border: '1px solid #333',
                    borderRadius: '8px',
                    color: 'white',
                    fontSize: '14px'
                  }}
                >
                  <option value="New">New</option>
                  <option value="Like New">Like New</option>
                  <option value="Good">Good</option>
                  <option value="Fair">Fair</option>
                  <option value="Poor">Poor</option>
                </select>
              </div>
              <div style={{ marginBottom: '12px' }}>
                <input
                  type="text"
                  value={formData.category}
                  onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                  placeholder="Category (e.g. Football, Cricket)"
                  style={{
                    width: '100%',
                    padding: '12px',
                    background: '#1a1a1a',
                    border: '1px solid #333',
                    borderRadius: '8px',
                    color: 'white',
                    fontSize: '14px'
                  }}
                />
              </div>
              <button
                type="submit"
                style={{
                  width: '100%',
                  padding: '12px',
                  background: 'linear-gradient(to right, #c8a200, #FFD700)',
                  border: 'none',
                  borderRadius: '8px',
                  color: '#0a0a0a',
                  fontWeight: 'bold',
                  cursor: 'pointer'
                }}
              >
                Post Listing
              </button>
            </form>
          </div>
        )}

        {/* Listings */}
        {loading ? (
          <div style={{ textAlign: 'center', color: '#666', padding: '40px' }}>Loading...</div>
        ) : listings.length === 0 ? (
          <div style={{
            background: '#0d0d0d',
            border: '1px solid #c8a20020',
            borderRadius: '12px',
            padding: '40px',
            textAlign: 'center',
            color: '#666'
          }}>
            <div style={{ fontSize: '48px', marginBottom: '16px' }}>🛒</div>
            <h3 style={{ color: '#888' }}>No listings available</h3>
            <p>Be the first to sell something!</p>
          </div>
        ) : (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '16px' }}>
            {listings.map((item) => (
              <div key={item.id} style={{
                background: '#0d0d0d',
                border: '1px solid #c8a20020',
                borderRadius: '12px',
                padding: '16px',
                transition: 'all 0.3s'
              }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                  <h3 style={{ fontSize: '16px', fontWeight: 'bold' }}>{item.item_name}</h3>
                  <span style={{
                    background: '#1a3a1a',
                    color: '#52c07a',
                    padding: '2px 8px',
                    borderRadius: '12px',
                    fontSize: '10px',
                    fontWeight: 'bold'
                  }}>
                    {item.condition}
                  </span>
                </div>
                {item.category && (
                  <p style={{ color: '#666', fontSize: '12px' }}>📁 {item.category}</p>
                )}
                {item.description && (
                  <p style={{ color: '#888', fontSize: '13px', margin: '8px 0' }}>
                    {item.description.length > 60 ? item.description.substring(0, 60) + '...' : item.description}
                  </p>
                )}
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '12px' }}>
                  <span style={{ color: '#FFD700', fontSize: '20px', fontWeight: 'bold' }}>
                    ${item.price}
                  </span>
                  <button
                    onClick={() => handleBuy(item)}
                    disabled={item.seller_id === currentUser?.id}
                    style={{
                      padding: '6px 16px',
                      background: item.seller_id === currentUser?.id ? '#333' : '#c8a200',
                      color: item.seller_id === currentUser?.id ? '#666' : '#0a0a0a',
                      border: 'none',
                      borderRadius: '8px',
                      fontWeight: 'bold',
                      cursor: item.seller_id === currentUser?.id ? 'not-allowed' : 'pointer',
                      fontSize: '13px'
                    }}
                  >
                    {item.seller_id === currentUser?.id ? 'Your Item' : 'Buy Now'}
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}
